	@Test
	public void circularBufferUsesFullConfiguredCapacity() {
		LmdbSailStore.CircularBuffer<Integer> buffer = new LmdbSailStore.CircularBuffer<>(4);

		assertTrue(buffer.add(1));
		assertTrue(buffer.add(2));
		assertTrue(buffer.add(3));
		assertTrue(buffer.add(4));
		assertFalse(buffer.add(5));

		assertEquals(Integer.valueOf(1), buffer.remove());
		assertEquals(Integer.valueOf(2), buffer.remove());
		assertEquals(Integer.valueOf(3), buffer.remove());
		assertEquals(Integer.valueOf(4), buffer.remove());
		assertNull(buffer.remove());
	}

